import{_ as a,o as e,c as n,a2 as i}from"./chunks/framework.C24VBsJ9.js";const b=JSON.parse('{"title":"UUU + UMS eMMC 烧录","description":"","frontmatter":{"title":"UUU + UMS eMMC 烧录"},"headers":[],"relativePath":"tutorial/flash/09_uuu_ums_emmc_flashing.md","filePath":"tutorial/flash/09_uuu_ums_emmc_flashing.md","lastUpdated":1781369075000}'),p={name:"tutorial/flash/09_uuu_ums_emmc_flashing.md"};function t(l,s,d,o,r,c){return e(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="uuu-ums-emmc-烧录实战-让板子把-emmc-借给主机" tabindex="-1">UUU + UMS eMMC 烧录实战 - 让板子把 eMMC 借给主机 <a class="header-anchor" href="#uuu-ums-emmc-烧录实战-让板子把-emmc-借给主机" aria-label="Permalink to &quot;UUU + UMS eMMC 烧录实战 - 让板子把 eMMC 借给主机&quot;">​</a></h1><h2 id="前言-emmc-不能像-sd-卡那样拔下来" tabindex="-1">前言：eMMC 不能像 SD 卡那样拔下来 <a class="header-anchor" href="#前言-emmc-不能像-sd-卡那样拔下来" aria-label="Permalink to &quot;前言：eMMC 不能像 SD 卡那样拔下来&quot;">​</a></h2><p>SD 卡烧录很直接：拿读卡器，找到 <code>/dev/sdX</code>，把整盘镜像写进去。</p><p>eMMC 就麻烦一点。它焊在板子上，不能拔下来插到主机。我们需要让板子自己帮忙：先通过 USB SDP 把 U-Boot 临时下载到 RAM 里运行，再让 U-Boot 执行 <code>ums 0 mmc 1</code>，把板上的 eMMC 伪装成一个 USB Mass Storage 设备暴露给主机。</p><p>这就是 UUU + UMS 流程。</p><p>这里有个边界一定要分清楚：UUU 这一步只是把 U-Boot 跑进内存。真正写入 eMMC 的动作，是主机对 UMS 暴露出来的块设备写 raw image。</p><h2 id="当前流程长什么样" tabindex="-1">当前流程长什么样 <a class="header-anchor" href="#当前流程长什么样" aria-label="Permalink to &quot;当前流程长什么样&quot;">​</a></h2><p>整个链路可以拆成四步：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主机 uuu</span></span>
<span class="line"><span>  -&gt; USB SDP 下载 u-boot-dtb.imx 到 RAM</span></span>
<span class="line"><span>  -&gt; U-Boot 运行 bootcmd_mfg</span></span>
<span class="line"><span>  -&gt; U-Boot 执行 ums 0 mmc 1 暴露 eMMC</span></span>
<span class="line"><span>  -&gt; 主机把 imx6ull-aes-emmc.img 写进新增块设备</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>项目里的 UUU 脚本是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tools/uuu/imx6ull-aes-ums.lst</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>内容很短：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>uuu_version 1.4.72</span></span>
<span class="line"><span>SDP: boot -f ../../out/release-latest/uboot/u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这个相对路径是按 <code>tools/uuu/</code> 目录来算的。之前 bring-up 里踩过一次坑：如果 lst 里直接写 <code>out/release-latest/...</code>，UUU 从 lst 所在目录解析路径时就会找不到文件。现在用 <code>../../out/...</code>，从 <code>tools/uuu/</code> 回到项目根目录，再进入 <code>out/</code>。</p><h2 id="先生成-emmc-镜像" tabindex="-1">先生成 eMMC 镜像 <a class="header-anchor" href="#先生成-emmc-镜像" aria-label="Permalink to &quot;先生成 eMMC 镜像&quot;">​</a></h2><p>从项目根目录执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/release-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --boot-media</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> emmc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者直接调用镜像脚本：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/image_builder/build_imx6ull_image.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --release-dir=out/release-latest</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --boot-media=emmc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>输出应该是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/images/imx6ull-aes-emmc.img</span></span>
<span class="line"><span>out/release-latest/images/imx6ull-aes-emmc.img.manifest</span></span>
<span class="line"><span>out/release-latest/images/imx6ull-aes-emmc.img.sha256</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>烧录前先看 manifest：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1,80p&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/images/imx6ull-aes-emmc.img.manifest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>重点确认：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>boot_media=emmc</span></span>
<span class="line"><span>uboot_mmc_dev=1</span></span>
<span class="line"><span>linux_root_dev=/dev/mmcblk1p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>eMMC 镜像和 SD 镜像的分区布局很像，但启动参数不是一回事。这里必须是 <code>mmc 1</code> 和 <code>/dev/mmcblk1p2</code>。</p><div class="tip custom-block"><p class="custom-block-title">v1.0.0 验证基线</p><p>UUU + UMS 写入 <code>imx6ull-aes-emmc.img</code> 并从 eMMC 启动的流程，已由仓库主作者 CharlieChen114514 在正点原子阿尔法 i.MX6ULL 开发板上实验通过。本章后续排查默认以 <code>mmc 1</code> 和 <code>root=/dev/mmcblk1p2</code> 为基线。</p></div><h2 id="确认临时-u-boot-是新的" tabindex="-1">确认临时 U-Boot 是新的 <a class="header-anchor" href="#确认临时-u-boot-是新的" aria-label="Permalink to &quot;确认临时 U-Boot 是新的&quot;">​</a></h2><p>UUU 加载的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/uboot/u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你刚改过 U-Boot 的 <code>bootcmd_mfg</code>，要先重新构建 U-Boot。否则 UUU 跑起来的还是旧环境，可能会掉进旧的 <code>fastboot 0</code> 流程。</p><p>当然，现场已经是旧环境也不是完全没救。只要还能进 U-Boot 命令行，或者旧 U-Boot 里还有 <code>ums</code> 命令，就可以先把 eMMC 暴露出来，手动热更新 boot 分区里的内核/设备树，再把新的 <code>u-boot-dtb.imx</code> 写回 raw U-Boot 区域。</p><p>这里一定要分清楚两件事：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>zImage / imx6ull-aes.dtb  -&gt; boot 分区里的普通文件</span></span>
<span class="line"><span>u-boot-dtb.imx            -&gt; eMMC 起始区域的 raw bootloader，偏移 1 KiB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>也就是说，把 <code>u-boot-dtb.imx</code> 拷进 boot 分区只是“放了一个文件”，板子下次上电不会自动从这个文件启动。真正热更新 U-Boot，还要执行后面的 raw 写入步骤。</p><p>可以用 <code>strings</code> 粗看一下镜像里有没有 UMS 命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/uboot/u-boot-dtb.imx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;bootcmd_mfg|ums 0 mmc&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>期望能看到类似：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bootcmd_mfg=... mmc dev \${emmc_dev}; ums 0 mmc \${emmc_dev};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一步不是严格校验，只是一个很实用的现场检查。至少能避免“我以为烧的是新 U-Boot，其实 UUU 还在跑旧镜像”。</p><h2 id="旧-u-boot-下的热更新方法" tabindex="-1">旧 U-Boot 下的热更新方法 <a class="header-anchor" href="#旧-u-boot-下的热更新方法" aria-label="Permalink to &quot;旧 U-Boot 下的热更新方法&quot;">​</a></h2><p>这节适合这种情况：板子里现在跑的是旧 U-Boot，<code>bootcmd_mfg</code> 还不对，没法优雅地自动进入 UMS，但你还能进 U-Boot 命令行。</p><p>先在 U-Boot 里手动暴露 eMMC：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc dev 1</span></span>
<span class="line"><span>ums 0 mmc 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>回到主机，先确认新增的整盘设备。还是老规矩，进入 UMS 前后各看一次：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>假设新增设备是 <code>/dev/sdX</code>。如果系统自动挂载了 boot 分区，可以直接用文件管理器替换文件；如果没有自动挂载，就手动挂载：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt/imx6ull-emmc-boot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdX1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt/imx6ull-emmc-boot</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>替换 boot 分区里的内核、设备树，并顺手放一份新的 U-Boot 文件进去：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/linux/arch/arm/boot/zImage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  /mnt/imx6ull-emmc-boot/zImage</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/linux/arch/arm/boot/dts/nxp/imx/imx6ull-aes.dtb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  /mnt/imx6ull-emmc-boot/imx6ull-aes.dtb</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/uboot/u-boot-dtb.imx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  /mnt/imx6ull-emmc-boot/u-boot-dtb.imx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>如果这个 boot 分区里还有 <code>/boot/</code> 目录，也可以同步放一份，方便兼容不同启动命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt/imx6ull-emmc-boot/boot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/linux/arch/arm/boot/zImage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  /mnt/imx6ull-emmc-boot/boot/zImage</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/linux/arch/arm/boot/dts/nxp/imx/imx6ull-aes.dtb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  /mnt/imx6ull-emmc-boot/boot/imx6ull-aes.dtb</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>卸载分区：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> umount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /mnt/imx6ull-emmc-boot</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>到这里，内核和设备树已经更新了，但 U-Boot 还没有真正更新。接下来有两种写 raw U-Boot 的办法。</p><p>第一种是在主机侧直接对 UMS 暴露出来的整盘设备写 raw 区域：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=out/release-latest/uboot/u-boot-dtb.imx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  of=/dev/sdX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  bs=1K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  seek=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  conv=notrunc,fsync</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这条命令对应镜像构建脚本里的动作：从整盘偏移 <code>1 KiB</code> 处写入 <code>u-boot-dtb.imx</code>。<code>of=</code> 必须是整盘设备 <code>/dev/sdX</code>，不是 <code>/dev/sdX1</code>。</p><p>第二种是先把 <code>u-boot-dtb.imx</code> 放进 boot 分区，再回到 U-Boot 里从 boot 分区加载它，然后写到 eMMC raw 区域。先在主机算一下需要写多少个 512 字节块：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">size</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c%s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/uboot/u-boot-dtb.imx</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;filesize=%d bytes, block_count=0x%x\\n&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &quot;$(( (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> + </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">511</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 512</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ))&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>它会输出类似：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>filesize=786432 bytes, block_count=0x600</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>回到 U-Boot，执行下面这组命令。最后一个参数要换成你刚才算出来的 <code>block_count</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc dev 1</span></span>
<span class="line"><span>ext4load mmc 1:1 \${loadaddr} /u-boot-dtb.imx</span></span>
<span class="line"><span>mmc write \${loadaddr} 0x2 0x600</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这里的 <code>0x2</code> 是写入起始块号。因为 raw U-Boot 偏移是 <code>1 KiB</code>，而 eMMC 块大小按 <code>512</code> 字节算：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 KiB / 512 = 2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>最后断电重启，重新进 U-Boot 看环境：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>printenv bootcmd_mfg</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果能看到 <code>ums 0 mmc 1</code>，说明新的 U-Boot 默认环境已经生效。</p><h2 id="通过-uuu-进入-ums" tabindex="-1">通过 UUU 进入 UMS <a class="header-anchor" href="#通过-uuu-进入-ums" aria-label="Permalink to &quot;通过 UUU 进入 UMS&quot;">​</a></h2><p>让板子进入 USB SDP / mfgtools 启动模式，接好 USB 线，然后在项目根目录执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uuu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tools/uuu/imx6ull-aes-ums.lst</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果主机权限已经配置好，也可以不加 <code>sudo</code>。</p><p>正常流程里，UUU 把 U-Boot 下载到 RAM，U-Boot 检测到制造模式启动后会执行：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc dev 1</span></span>
<span class="line"><span>ums 0 mmc 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这时主机上再看块设备：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该能看到一个新增的整盘设备。它可能是 <code>/dev/sdb</code>、<code>/dev/sdc</code>，也可能在 WSL/USB 转发环境里表现得更绕一点。判断方法还是一样：运行 UUU 前看一次 <code>lsblk</code>，进入 UMS 后再看一次，新增的整盘设备才是目标。</p><h2 id="把-emmc-镜像写进-ums-设备" tabindex="-1">把 eMMC 镜像写进 UMS 设备 <a class="header-anchor" href="#把-emmc-镜像写进-ums-设备" aria-label="Permalink to &quot;把 eMMC 镜像写进 UMS 设备&quot;">​</a></h2><p>假设新增设备是 <code>/dev/sdX</code>，先卸载它可能被自动挂载的分区：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> umount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdX1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> umount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/sdX2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>然后写入整盘镜像：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=out/release-latest/images/imx6ull-aes-emmc.img</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  of=/dev/sdX</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  bs=4M</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  status=progress</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  conv=fsync</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>写完同步：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sync</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里还是那句话：<code>of=</code> 必须是整盘设备。不要只往弹出来的盘符里复制 <code>zImage</code>、DTB，也不要写到 <code>/dev/sdX1</code>。完整镜像里包含 raw U-Boot、MBR 分区表、boot 分区和 rootfs 分区；文件复制只会更新分区里的普通文件，补不上 raw 区域。</p><p>如果用 Rufus，也选择 UMS 暴露出来的 eMMC 设备，并使用 DD/raw image 模式写：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/images/imx6ull-aes-emmc.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="切回-emmc-启动" tabindex="-1">切回 eMMC 启动 <a class="header-anchor" href="#切回-emmc-启动" aria-label="Permalink to &quot;切回 eMMC 启动&quot;">​</a></h2><p>写入完成后，安全弹出或确保 <code>sync</code> 完成。然后断电，把启动模式切回 eMMC，再上电。</p><p>进入 U-Boot 后可以先检查：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc list</span></span>
<span class="line"><span>mmc dev 1</span></span>
<span class="line"><span>mmc part</span></span>
<span class="line"><span>ext4ls mmc 1:1 /</span></span>
<span class="line"><span>ext4ls mmc 1:2 /</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果环境里有 <code>emmcbootaes</code>：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>run emmcbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果环境里没有，可以快速设置一套：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># eMMC 快速启动环境设置</span></span>
<span class="line"><span>setenv emmc_dev 1</span></span>
<span class="line"><span>setenv fdt_addr 0x83000000</span></span>
<span class="line"><span>setenv emmcargs &#39;setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk1p2 rootwait rw&#39;</span></span>
<span class="line"><span>setenv loademmcimage &#39;ext4load mmc \${emmc_dev}:1 \${loadaddr} /zImage&#39;</span></span>
<span class="line"><span>setenv loademmcfdt &#39;ext4load mmc \${emmc_dev}:1 \${fdt_addr} /imx6ull-aes.dtb&#39;</span></span>
<span class="line"><span>setenv emmcbootaes &#39;echo Booting AES from eMMC ...; run emmcargs; mmc dev \${emmc_dev}; run loademmcimage; run loademmcfdt; bootz \${loadaddr} - \${fdt_addr}&#39;</span></span>
<span class="line"><span>saveenv</span></span>
<span class="line"><span>run emmcbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>手动启动兜底（不依赖预设环境变量）：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk1p2 rootfstype=ext4 rootwait rw</span></span>
<span class="line"><span>ext4load mmc 1:1 \${loadaddr} /zImage</span></span>
<span class="line"><span>ext4load mmc 1:1 \${fdt_addr} /imx6ull-aes.dtb</span></span>
<span class="line"><span>bootz \${loadaddr} - \${fdt_addr}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这里最关键的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc 1:1</span></span>
<span class="line"><span>root=/dev/mmcblk1p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果串口里显示内核加载成功，但挂 rootfs 失败，第一眼就看这个 root 参数。</p><h2 id="ums-流程里最容易混的两块-u-boot" tabindex="-1">UMS 流程里最容易混的两块 U-Boot <a class="header-anchor" href="#ums-流程里最容易混的两块-u-boot" aria-label="Permalink to &quot;UMS 流程里最容易混的两块 U-Boot&quot;">​</a></h2><p>这个地方很容易绕，我们单独说清楚。</p><p>UUU 下载到 RAM 的 U-Boot，只负责临时把 eMMC 暴露出来。它不会自动写进 eMMC。</p><p>真正被烧进 eMMC 的 U-Boot，是 <code>imx6ull-aes-emmc.img</code> 里 1 KiB 偏移处的那份 <code>u-boot-dtb.imx</code>。</p><p>所以如果你改了 U-Boot，至少要确认两件事：</p><p>第一，<code>out/release-latest/uboot/u-boot-dtb.imx</code> 已经重新生成。否则 UUU 临时启动的 U-Boot 可能还是旧的。</p><p>第二，<code>out/release-latest/images/imx6ull-aes-emmc.img</code> 已经重新生成。否则写进 eMMC 的 raw U-Boot 仍然是旧的。</p><p>这也是 bring-up 里专门记下来的 caveat：临时 UUU U-Boot 只在 RAM 里跑，不能代表 eMMC 已经更新。</p><h2 id="常见现象" tabindex="-1">常见现象 <a class="header-anchor" href="#常见现象" aria-label="Permalink to &quot;常见现象&quot;">​</a></h2><h3 id="uuu-找不到-u-boot-dtb-imx" tabindex="-1">UUU 找不到 u-boot-dtb.imx <a class="header-anchor" href="#uuu-找不到-u-boot-dtb-imx" aria-label="Permalink to &quot;UUU 找不到 u-boot-dtb.imx&quot;">​</a></h3><p>看 <code>tools/uuu/imx6ull-aes-ums.lst</code> 里的路径。当前应为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SDP: boot -f ../../out/release-latest/uboot/u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>同时确认文件存在：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest/uboot/u-boot-dtb.imx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="u-boot-没有进入-ums-而是进了-fastboot" tabindex="-1">U-Boot 没有进入 UMS，而是进了 fastboot <a class="header-anchor" href="#u-boot-没有进入-ums-而是进了-fastboot" aria-label="Permalink to &quot;U-Boot 没有进入 UMS，而是进了 fastboot&quot;">​</a></h3><p>这通常说明 <code>bootcmd_mfg</code> 还是旧的。进入 U-Boot 后可以看：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>printenv bootcmd_mfg</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>期望里面有：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ums 0 mmc 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果还是 <code>fastboot 0</code>，就需要更新板级默认环境，重新构建 U-Boot，并重新生成 eMMC 镜像。</p><h3 id="主机看不到新增块设备" tabindex="-1">主机看不到新增块设备 <a class="header-anchor" href="#主机看不到新增块设备" aria-label="Permalink to &quot;主机看不到新增块设备&quot;">​</a></h3><p>先确认 U-Boot 里 <code>ums 0 mmc 1</code> 已经跑起来。如果 U-Boot 卡在命令行，可以手动执行：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mmc dev 1</span></span>
<span class="line"><span>ums 0 mmc 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>主机侧再看：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsblk</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -40</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果仍然没有新增设备，就回到 USB 线、板卡 USB 口、虚拟机或 WSL USB 转发这些外部因素上排查。</p><h3 id="emmc-启动时-vfs-找不到-root" tabindex="-1">eMMC 启动时 VFS 找不到 root <a class="header-anchor" href="#emmc-启动时-vfs-找不到-root" aria-label="Permalink to &quot;eMMC 启动时 VFS 找不到 root&quot;">​</a></h3><p>eMMC 流程应该是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root=/dev/mmcblk1p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果实际板卡枚举和项目约定不一致，可以临时试一下：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk0p2 rootfstype=ext4 rootwait rw</span></span>
<span class="line"><span>run emmcbootaes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>但这只能作为现场判断，不建议长期靠猜设备号。最终还是要把项目里的镜像生成参数、U-Boot 环境和板卡实际枚举统一起来。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>到这里，SD 和 eMMC 两条烧录路径都走通了。后面再遇到启动问题，就可以按层次拆：镜像 manifest、主机写盘设备、U-Boot 能不能读 boot 分区、Linux root 参数是否匹配。</p><p>后续现场操作时，命令速查可以看：<a href="./../commands/04_flashing_commands">烧录命令速查</a>。</p>`,136)])])}const u=a(p,[["render",t]]);export{b as __pageData,u as default};
